// gen_kernel_organs — authoring-time generator for the kernel's "organs".
//
// Each kernel primitive that we want to source from a single equation-of-truth
// is built here as an `Expr` tree and emitted (via eqc-rs) to committed,
// hand-inspectable Rust. The emitted source is pasted into
// `kernel/src/eqc_gen.rs` (carrying the "GENERATED by eqc-rs" header) — the
// generated code has ZERO runtime dependency on this crate or on eqc-rs.
//
// See BLUEPRINT-P-A §3.1 (A2 — the template organ).

use eqc_rs::{Equation, Expr};

fn main() {
    // A2 — ema_next: prev + alpha*(sample - prev)
    let (prev, sample, alpha) = (Expr::sym("prev"), Expr::sym("sample"), Expr::sym("alpha"));
    let ema = Equation::new(
        "ema_next",
        &["prev", "sample", "alpha"],
        prev.clone() + alpha * (sample - prev),
    );
    println!("{}", ema.emit_f64_rust().expect("emit ema_next"));
}
